#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
    void heapify(vector<int>& nums, int n) {
        for (int i = n / 2 - 1; i >= 0; --i) {
            _heapify(nums, n, i);
        }
        for (int i = n - 1; i > 0; --i) {
            swap(nums[0], nums[i]);
            _heapify(nums, i, 0);
        }
    }

    void _heapify(vector<int>& nums, int n, int i) {
        int largest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        if (left < n && nums[left] > nums[largest]) {
            largest = left;
        }
        if (right < n && nums[right] > nums[largest]) {
            largest = right;
        }
        if (largest != i) {
            swap(nums[i], nums[largest]);
            _heapify(nums, n, largest);
        }
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }
    Solution solution;
    solution.heapify(nums, n);
    for (int i : nums) {
        cout << i << ' ';
    }
    cout << endl;
    return 0;
}
